/** Normaliza una cadena de región para usarla como clave (sin tildes, sin espacios, mayúsculas) */
export const getNormalizeKey = (str: string): string =>
  (str || '')
    .toUpperCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/\s+/g, '_')
    .trim();

